# Create a zero-dollar cost budget with email alert via AWS CLI
aws budgets create-budget \
  --account-id $(aws sts get-caller-identity --query Account --output text) \
  --budget '{
    "BudgetName": "FreeTierGuard",
    "BudgetLimit": {"Amount": "0.01", "Unit": "USD"},
    "TimeUnit": "MONTHLY",
    "BudgetType": "COST"
  }' \
  --notifications-with-subscribers '[{
    "Notification": {
      "NotificationType": "ACTUAL",
      "ComparisonOperator": "GREATER_THAN",
      "Threshold": 0,
      "ThresholdType": "ABSOLUTE_VALUE"
    },
    "Subscribers": [{
      "SubscriptionType": "EMAIL",
      "Address": "your-email@example.com"
    }]
  }]'

import boto3
from datetime import datetime, timedelta

def get_free_tier_usage_summary():
    """Return current month Free Tier usage percentage for key services."""
    ce = boto3.client("ce", region_name="us-east-1")

    # Get the current month date range
    today = datetime.utcnow()
    start = today.replace(day=1).strftime("%Y-%m-%d")
    end = today.strftime("%Y-%m-%d")

    response = ce.get_cost_and_usage(
        TimePeriod={"Start": start, "End": end},
        Granularity="MONTHLY",
        Metrics=["UsageQuantity"],
        GroupBy=[
            {"Type": "DIMENSION", "Key": "SERVICE"},
            {"Type": "DIMENSION", "Key": "USAGE_TYPE"},
        ],
        Filter={
            "Dimensions": {
                "Key": "RECORD_TYPE",
                "Values": ["Usage"],
            }
        },
    )

    # Filter for free tier usage types (contain "FreeUsage" or "Free")
    free_tier_usage = []
    for result in response["ResultsByTime"]:
        for group in result["Groups"]:
            service, usage_type = group["Keys"]
            if "free" in usage_type.lower() or "freetier" in usage_type.lower():
                amount = float(group["Metrics"]["UsageQuantity"]["Amount"])
                if amount > 0:
                    free_tier_usage.append({
                        "service": service,
                        "usage_type": usage_type,
                        "amount": amount,
                    })

    return free_tier_usage

# Get Free Tier status
usage = get_free_tier_usage_summary()
for item in sorted(usage, key=lambda x: x["amount"], reverse=True):
    print(f"{item['service']:40} {item['usage_type']:50} {item['amount']:.2f}")
